import type { filterFieldMessages } from '../../messages.js';
import type {
  FilterFieldCustomTypes,
  FilterFieldValuePredicate,
} from '../../types/validation.js';

const builtInTypeLabelKeys: Record<
  string,
  keyof typeof filterFieldMessages.linting.typeLabels
> = {
  Duration: 'Durations',
  Number: 'Numbers',
  String: 'Strings',
  IPAddress: 'IPAddresses',
  UID: 'UIDs',
  Timestamp: 'Timestamps',
  SmartscapeId: 'SmartscapeIds',
  Boolean: 'Boolean',
};

/** @internal */
export function getTypeLabelKey(
  type: string,
): keyof typeof filterFieldMessages.linting.typeLabels | undefined {
  return builtInTypeLabelKeys[type];
}

/** @internal */
export function getCustomTypeLabel(
  type: string,
  customTypes?: FilterFieldCustomTypes,
): string | undefined {
  if (!customTypes) {
    return undefined;
  }
  const customType = customTypes[type];
  if (customType && typeof customType === 'object' && customType.label) {
    return customType.label;
  }
  return undefined;
}

/** @internal */
export function isCustomType(type: string): boolean {
  return !builtInTypeLabelKeys[type] && type !== 'Any' && type !== 'JSONPath';
}

/** @internal */
export function getErrorMessageForType(
  type: FilterFieldValuePredicate | undefined,
): string {
  switch (type) {
    case 'Boolean':
      return 'invalidValueErrorBoolean';
    case 'Duration':
      return 'invalidValueErrorDurations';
    case 'Number':
      return 'invalidValueErrorNumbers';
    case 'IPAddress':
      return 'invalidValueErrorIPAddresses';
    case 'UID':
      return 'invalidValueErrorUIDs';
    case 'SmartscapeId':
      return 'invalidValueErrorSmartscapeIds';
    case 'Timestamp':
      return 'invalidValueErrorTimestamps';
    case 'String':
      return 'invalidValueErrorStrings';
    case 'Any':
    default:
      return 'invalidValueErrorGeneric';
  }
}
